from pydantic import BaseModel, Field

class ExtractedClaims(BaseModel):
    claims: list[str] = Field(description="Factual claims extracted from the text")
    source_quality: str = Field(description="high / medium / low")

class VerifiedClaim(BaseModel):
    claim: str
    plausibility: str       # HIGH / MEDIUM / LOW
    reason: str

class VerificationResult(BaseModel):
    verified_claims: list[VerifiedClaim]

class EditorialSummary(BaseModel):
    summary: str
    confidence: str         # HIGH / MEDIUM / LOW

# Structured chains
structured_extract = (
    ChatPromptTemplate.from_messages([
        ("system", "Extract factual claims and rate the source quality."),
        ("human", "{article}"),
    ])
    | llm.with_structured_output(ExtractedClaims)
)

structured_verify = (
    ChatPromptTemplate.from_messages([
        ("system", "Rate each claim's plausibility with a one-sentence reason."),
        ("human", "Claims to verify: {claims}"),
    ])
    | llm.with_structured_output(VerificationResult)
)

structured_summarise = (
    ChatPromptTemplate.from_messages([
        ("system", "Write an editorial summary and overall confidence level."),
        ("human", "Verified claims: {verified_claims}"),
    ])
    | llm.with_structured_output(EditorialSummary)
)

# Compose with field access between steps
structured_pipeline = (
    structured_extract
    | RunnableLambda(lambda r: {
        "claims": "\n".join(f"- {c}" for c in r.claims),
      })
    | structured_verify
    | RunnableLambda(lambda r: {
        "verified_claims": str([
            f"{vc.claim} ({vc.plausibility})" for vc in r.verified_claims
        ])
      })
    | structured_summarise
)

summary: EditorialSummary = structured_pipeline.invoke({"article": article})
print(f"Summary: {summary.summary}")
print(f"Confidence: {summary.confidence}")
